// Parse AI triage response
const response = $input.first().json.output || $input.first().json.text || '';

let severity = 'Unknown';
let category = 'Unknown';
let summary = 'Unable to parse';
let actions = 'None specified';
let riskScore = 0;

// Extract fields from response
const severityMatch = response.match(/SEVERITY:\s*(Critical|High|Medium|Low)/i);
if (severityMatch) severity = severityMatch[1];

const categoryMatch = response.match(/CATEGORY:\s*([^\n]+)/i);
if (categoryMatch) category = categoryMatch[1].trim();

const summaryMatch = response.match(/SUMMARY:\s*([^\n]+)/i);
if (summaryMatch) summary = summaryMatch[1].trim();

const actionsMatch = response.match(/IMMEDIATE_ACTIONS:\s*([^\n]+)/i);
if (actionsMatch) actions = actionsMatch[1].trim();

const scoreMatch = response.match(/RISK_SCORE:\s*(\d+)/i);
if (scoreMatch) riskScore = parseInt(scoreMatch[1]);

return [{
  json: {
    severity,
    category,
    summary,
    immediate_actions: actions,
    risk_score: riskScore,
    raw_response: response,
    timestamp: new Date().toISOString()
  }
}];

