// Parse validation response and generate final report
const validationResponse = $input.first().json.output || $input.first().json.text || '';

let validation = 'Unknown';
let reason = 'Unable to parse';
let adjustedSeverity = 'Same';

const validMatch = validationResponse.match(/VALIDATION:\s*(Correct|Incorrect)/i);
if (validMatch) validation = validMatch[1];

const reasonMatch = validationResponse.match(/REASON:\s*([^\n]+)/i);
if (reasonMatch) reason = reasonMatch[1].trim();

const adjMatch = validationResponse.match(/ADJUSTED_SEVERITY:\s*(Critical|High|Medium|Low|Same)/i);
if (adjMatch) adjustedSeverity = adjMatch[1];

return [{
  json: {
    validation_result: validation,
    validation_reason: reason,
    adjusted_severity: adjustedSeverity,
    raw_validation: validationResponse,
    final_report: `\n========== FINAL SECURITY INCIDENT REPORT ==========\n\n✅ Validation: ${validation}\n📝 Reason: ${reason}\n🔄 Severity Adjustment: ${adjustedSeverity}\n\n====================================================\n`,
    completed_at: new Date().toISOString()
  }
}];
